            DailyEntry { date: "2025-01-01".into(), messages: 10, conversations: 1 },
            DailyEntry { date: "2025-01-02".into(), messages: 20, conversations: 2 },
        ];

        let weekly = aggregate_to_weekly(&daily);

        assert_eq\!(weekly.len(), 1);
        assert_eq\!(weekly[0].messages, 30);
    }

    #[test]
    fn test_top_terms_extraction() {
        let db = create_test_db();
        db.execute("INSERT INTO conversations (title) VALUES (?)", ["Debug authentication flow"]).unwrap();
        db.execute("INSERT INTO conversations (title) VALUES (?)", ["Fix authentication bug"]).unwrap();

        let gen = AnalyticsGenerator::new(&db);
        let top = gen.generate_top_terms().unwrap();

        assert\!(top.terms.iter().any(|(term, _)| term == "authentication"));
    }
